// Parse Registration CSV
// Reads the CSV text returned by the "Fetch Registration CSV" HTTP node and
// turns it into one item per row. Handles VFB Pro quirks: quoted multi-line
// fields, embedded HTML in column labels, and trailing whitespace in headers.

const input = $input.all();
const raw = input.length ? String(input[0].json.data || input[0].json.body || input[0].json.text || '') : '';

function parseCSV(text) {
  const rows = [];
  let field = '';
  let row = [];
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (inQuotes) {
      if (ch === '"') {
        if (text[i + 1] === '"') { field += '"'; i++; }
        else { inQuotes = false; }
      } else {
        field += ch;
      }
    } else {
      if (ch === '"') { inQuotes = true; }
      else if (ch === ',') { row.push(field); field = ''; }
      else if (ch === '\r') { /* ignore, handled on \n */ }
      else if (ch === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
      else { field += ch; }
    }
  }
  if (field.length > 0 || row.length > 0) { row.push(field); rows.push(row); }
  return rows;
}

function cleanHeader(h) {
  return String(h)
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/\s+/g, ' ')
    .trim();
}

const grid = parseCSV(raw);
if (grid.length === 0) {
  return [];
}
const headers = grid[0].map(cleanHeader);
const out = [];
for (let r = 1; r < grid.length; r++) {
  const cells = grid[r];
  if (cells.length === 1 && String(cells[0]).trim() === '') { continue; }
  const obj = {};
  for (let c = 0; c < headers.length; c++) {
    obj[headers[c]] = cells[c] !== undefined ? String(cells[c]).trim() : '';
  }
  out.push({ json: obj });
}
return out;

// Strip PII from Registration
// HARD PRIVACY BOUNDARY. Sensitive student fields are dropped here and never
// pass downstream. Only the whitelisted follow-up fields are emitted, mapped to
// the shared leads-tab schema. Missing expected columns are logged, not
// silently ignored.

const items = $input.all();

function norm(s) {
  return String(s).toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
}

// A column is DROPPED (never emitted) when its header matches a sensitive
// field. Note that "Student's Homeroom Teacher" must be KEPT, so the student
// rule requires both "student" and "name" rather than "student" alone.
function isDropped(header) {
  const h = norm(header);
  if (h.indexOf('date of birth') !== -1 || h.indexOf('birth') !== -1) { return true; }
  if (h.indexOf('address') !== -1) { return true; }
  if (h.indexOf('allerg') !== -1 || h.indexOf('medical') !== -1) { return true; }
  if (h.indexOf('authorized to pick') !== -1 || h.indexOf('other adults') !== -1) { return true; }
  if (h.indexOf('emergency') !== -1) { return true; }
  if (h.indexOf('student') !== -1 && h.indexOf('name') !== -1) { return true; }
  return false;
}

// Find the value of the first column whose normalized header contains ALL of
// the given words. Dropped columns are never eligible.
function pick(obj, wordSets) {
  const keys = Object.keys(obj);
  for (const words of wordSets) {
    for (const k of keys) {
      if (isDropped(k)) { continue; }
      const nk = norm(k);
      if (words.every((w) => nk.indexOf(norm(w)) !== -1)) {
        return String(obj[k]).trim();
      }
    }
  }
  return '';
}

function parseCurrency(v) {
  if (v === undefined || v === null) { return 0; }
  const cleaned = String(v).replace(/[$,\s]/g, '');
  const n = parseFloat(cleaned);
  return isNaN(n) ? 0 : n;
}

const out = [];
let missingWarned = false;

for (const item of items) {
  const row = item.json || {};

  const entry_id = pick(row, [['entry', 'id'], ['id']]);
  const entry_date = pick(row, [['entry', 'date'], ['date', 'submitted'], ['date']]);
  const name = pick(row, [['parent', 'name'], ['guardian', 'name'], ['guardian'], ['parent']]);
  const email = pick(row, [['parent', 'email'], ['guardian', 'email'], ['email']]);
  const school = pick(row, [['school', 'name'], ['school']]);
  const grade = pick(row, [['grade']]);
  const homeroom_teacher = pick(row, [['homeroom'], ['teacher']]);
  const amount_usd = parseCurrency(pick(row, [['register', 'pay'], ['amount'], ['pay']]));

  // Never emit a dropped field even by accident: build a fresh object.
  const lead = {
    entry_id: entry_id,
    entry_date: entry_date,
    source: 'registration',
    name: name,
    email: email,
    school: school,
    grade: grade,
    homeroom_teacher: homeroom_teacher,
    amount_usd: amount_usd,
    category: '',
    sentiment: '',
    summary: ''
  };

  if (!missingWarned) {
    const missing = [];
    if (!entry_id) { missing.push('Entry ID'); }
    if (!name) { missing.push('Parent/Guardian Name'); }
    if (!email) { missing.push('Parent Email'); }
    if (missing.length > 0) {
      console.warn('Registration schema warning: expected columns not found: ' + missing.join(', ') + '. The VFB Pro export layout may have changed.');
      missingWarned = true;
    }
  }

  out.push({ json: lead });
}

return out;

// Aggregate Registration
// Groups the PII-stripped rows by month (YYYY-MM of Entry Date) and by school,
// then counts enrollments and sums revenue. Emits one row per group in the
// shared aggregates-tab schema.

const items = $input.all();

function monthKey(dateStr) {
  const s = String(dateStr || '').trim();
  // Fast path for ISO-like values (2024-05-01 ...).
  const iso = s.match(/^(\d{4})-(\d{2})/);
  if (iso) { return iso[1] + '-' + iso[2]; }
  const d = new Date(s);
  if (!isNaN(d.getTime())) {
    const m = String(d.getMonth() + 1).padStart(2, '0');
    return d.getFullYear() + '-' + m;
  }
  return 'unknown';
}

const groups = {};
for (const item of items) {
  const row = item.json || {};
  const dk = monthKey(row.entry_date);
  const school = String(row.school || '').trim() || 'unknown';
  const key = dk + '||' + school;
  if (!groups[key]) {
    groups[key] = { date_key: dk, school: school, enrollment_count: 0, revenue_usd: 0 };
  }
  groups[key].enrollment_count += 1;
  const amt = Number(row.amount_usd);
  groups[key].revenue_usd += isNaN(amt) ? 0 : amt;
}

const out = [];
for (const key of Object.keys(groups)) {
  const g = groups[key];
  out.push({
    json: {
      date_key: g.date_key,
      source: 'registration',
      school: g.school,
      enrollment_count: g.enrollment_count,
      revenue_usd: Math.round(g.revenue_usd * 100) / 100,
      message_count: '',
      category: '',
      sentiment: ''
    }
  });
}

return out;

// Parse Contact Us CSV
// The direct input to this node is the "Read Existing Leads" node (used later
// for deduplication), so the CSV text is pulled from the "Fetch Contact Us CSV"
// node by name. Same robust parser as the registration path: quoted multi-line
// message bodies, embedded HTML, and messy headers are all handled.

let raw = '';
try {
  const fetched = $('Fetch Contact Us CSV').all();
  raw = fetched.length ? String(fetched[0].json.data || fetched[0].json.body || fetched[0].json.text || '') : '';
} catch (e) {
  raw = '';
}

function parseCSV(text) {
  const rows = [];
  let field = '';
  let row = [];
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (inQuotes) {
      if (ch === '"') {
        if (text[i + 1] === '"') { field += '"'; i++; }
        else { inQuotes = false; }
      } else {
        field += ch;
      }
    } else {
      if (ch === '"') { inQuotes = true; }
      else if (ch === ',') { row.push(field); field = ''; }
      else if (ch === '\r') { /* ignore, handled on \n */ }
      else if (ch === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
      else { field += ch; }
    }
  }
  if (field.length > 0 || row.length > 0) { row.push(field); rows.push(row); }
  return rows;
}

function cleanHeader(h) {
  return String(h)
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/\s+/g, ' ')
    .trim();
}

const grid = parseCSV(raw);
if (grid.length === 0) {
  return [];
}
const headers = grid[0].map(cleanHeader);
const out = [];
for (let r = 1; r < grid.length; r++) {
  const cells = grid[r];
  if (cells.length === 1 && String(cells[0]).trim() === '') { continue; }
  const obj = {};
  for (let c = 0; c < headers.length; c++) {
    obj[headers[c]] = cells[c] !== undefined ? String(cells[c]).trim() : '';
  }
  out.push({ json: obj });
}
return out;

// Dedupe Against Sheet
// Normalizes each parsed Contact Us row into a stable schema and drops rows
// whose Entry ID already exists in the leads tab, so repeat runs never
// re-classify (and never re-bill the LLM). In BACKFILL_MODE every row passes.

const items = $input.all();

const backfill = $('Config').first().json.backfill_mode === true
  || String($('Config').first().json.backfill_mode) === 'true';

// Collect Entry IDs already stored in the leads tab. Missing/empty is fine.
const existing = new Set();
try {
  const rows = $('Read Existing Leads').all();
  for (const r of rows) {
    const id = r.json && (r.json.entry_id !== undefined ? r.json.entry_id : r.json['entry_id']);
    if (id !== undefined && id !== null && String(id).trim() !== '') {
      existing.add(String(id).trim());
    }
  }
} catch (e) {
  // Read node did not run or tab is empty: treat as no existing IDs.
}

function norm(s) {
  return String(s).toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
}

function pick(obj, includeSets, excludeWords) {
  const excl = (excludeWords || []).map(norm);
  const keys = Object.keys(obj);
  for (const words of includeSets) {
    for (const k of keys) {
      const nk = norm(k);
      if (excl.some((e) => nk.indexOf(e) !== -1)) { continue; }
      if (words.every((w) => nk.indexOf(norm(w)) !== -1)) {
        return String(obj[k]).trim();
      }
    }
  }
  return '';
}

const out = [];
for (const item of items) {
  const row = item.json || {};

  const entry_id = pick(row, [['entry', 'id'], ['id']]);
  const entry_date = pick(row, [['entry', 'date'], ['date', 'submitted'], ['date']]);
  const name = pick(row, [['first', 'name'], ['full', 'name'], ['name']], ['school', 'company', 'user', 'file']);
  const email = pick(row, [['email']]);
  const phone = pick(row, [['phone'], ['telephone'], ['mobile']]);
  const company_school = pick(row, [['company', 'school'], ['company'], ['school'], ['organization'], ['organisation']]);
  const subject = pick(row, [['subject'], ['topic'], ['reason']]);
  const message = pick(row, [['message'], ['comment'], ['inquiry'], ['enquiry'], ['body'], ['details'], ['question']]);

  if (!backfill && entry_id && existing.has(String(entry_id).trim())) {
    continue;
  }

  out.push({
    json: {
      entry_id: entry_id,
      entry_date: entry_date,
      name: name,
      email: email,
      phone: phone,
      company_school: company_school,
      subject: subject,
      message: message
    }
  });
}

return out;

// Apply Classification (runs once per item)
// Parses the Claude response for one Contact Us message, validates it against
// the allowed category and sentiment values, and merges it back with the
// original row. Any parse failure or out-of-range value falls back to safe
// defaults so a bad response never breaks the run.

const cfg = $('Config').first().json;
const categories = String(cfg.category_list || 'sponsor,school,volunteer,general,spam').split(',').map((s) => s.trim());
const sentiments = String(cfg.sentiment_list || 'positive,neutral,urgent').split(',').map((s) => s.trim());

// The original normalized row this classification belongs to.
const src = $('Dedupe Against Sheet').item.json;

// Pull the model's text out of the Anthropic /v1/messages response shape.
let text = '';
try {
  const resp = $json;
  if (resp && Array.isArray(resp.content) && resp.content.length > 0) {
    text = String(resp.content[0].text || '');
  } else if (resp && typeof resp.completion === 'string') {
    text = resp.completion;
  } else if (typeof resp === 'string') {
    text = resp;
  }
} catch (e) {
  text = '';
}

let category = 'general';
let sentiment = 'neutral';
let summary = '[classification failed]';

try {
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    const c = String(parsed.category || '').toLowerCase().trim();
    const s = String(parsed.sentiment || '').toLowerCase().trim();
    const sum = String(parsed.summary || '').trim();
    if (categories.indexOf(c) !== -1) { category = c; }
    if (sentiments.indexOf(s) !== -1) { sentiment = s; }
    if (sum) { summary = sum.length > 160 ? sum.slice(0, 157) + '...' : sum; }
  }
} catch (e) {
  // keep defaults
}

const lead = {
  entry_id: src.entry_id || '',
  entry_date: src.entry_date || '',
  source: 'contact_us',
  name: src.name || '',
  email: src.email || '',
  school: src.company_school || '',
  grade: '',
  homeroom_teacher: '',
  amount_usd: '',
  category: category,
  sentiment: sentiment,
  summary: summary
};

return { json: lead };

// Aggregate Contact Us
// Groups classified messages by month and category, counting messages and
// taking the majority sentiment per group. Emits rows in the shared
// aggregates-tab schema.

const items = $input.all();

function monthKey(dateStr) {
  const s = String(dateStr || '').trim();
  const iso = s.match(/^(\d{4})-(\d{2})/);
  if (iso) { return iso[1] + '-' + iso[2]; }
  const d = new Date(s);
  if (!isNaN(d.getTime())) {
    const m = String(d.getMonth() + 1).padStart(2, '0');
    return d.getFullYear() + '-' + m;
  }
  return 'unknown';
}

const groups = {};
for (const item of items) {
  const row = item.json || {};
  const dk = monthKey(row.entry_date);
  const category = String(row.category || 'general').trim() || 'general';
  const sentiment = String(row.sentiment || 'neutral').trim() || 'neutral';
  const key = dk + '||' + category;
  if (!groups[key]) {
    groups[key] = { date_key: dk, category: category, message_count: 0, sentiments: {} };
  }
  groups[key].message_count += 1;
  groups[key].sentiments[sentiment] = (groups[key].sentiments[sentiment] || 0) + 1;
}

const out = [];
for (const key of Object.keys(groups)) {
  const g = groups[key];
  let majority = 'neutral';
  let best = -1;
  for (const s of Object.keys(g.sentiments)) {
    if (g.sentiments[s] > best) { best = g.sentiments[s]; majority = s; }
  }
  out.push({
    json: {
      date_key: g.date_key,
      source: 'contact_us',
      school: '',
      enrollment_count: '',
      revenue_usd: '',
      message_count: g.message_count,
      category: g.category,
      sentiment: majority
    }
  });
}

return out;

// Build Weekly Summary
// Sends only on the configured day (default Sunday) and only once per day. The
// once-per-day guard reads the last-sent date from the "state" tab so a manual
// run and the scheduled run on the same day cannot both email. All day logic is
// evaluated in Pacific time regardless of the host clock.

const cfg = $('Config').first().json;
const sendDay = String(cfg.summary_send_day || 'sunday').trim().toLowerCase();

// Pacific-time date parts, independent of the container timezone.
const parts = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'America/Los_Angeles',
  year: 'numeric', month: '2-digit', day: '2-digit', weekday: 'long'
}).formatToParts(new Date());
const get = (t) => (parts.find((p) => p.type === t) || {}).value || '';
const todayStr = get('year') + '-' + get('month') + '-' + get('day');
const todayWeekday = get('weekday').toLowerCase();

// Gate 1: only the configured send day.
if (todayWeekday !== sendDay) {
  return [];
}

// Gate 2: only once per day. Look up the last-sent date in the state tab.
let lastSent = '';
try {
  const stateRows = $('Read Email State').all();
  for (const r of stateRows) {
    if (r.json && String(r.json.key).trim() === 'last_weekly_email_date') {
      lastSent = String(r.json.value || '').trim();
    }
  }
} catch (e) {
  lastSent = '';
}
if (lastSent === todayStr) {
  return [];
}

const items = $input.all();
const now = new Date();
const msPerDay = 24 * 60 * 60 * 1000;
const cutoff = new Date(now.getTime() - 7 * msPerDay);

function toDate(s) {
  const str = String(s || '').trim();
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}
function fmt(d) {
  return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
}

let regCount = 0;
let contactCount = 0;
let revenue = 0;
const catCounts = { sponsor: 0, school: 0, volunteer: 0, general: 0, spam: 0 };
const urgent = [];

for (const item of items) {
  const row = item.json || {};
  const d = toDate(row.entry_date);
  if (!d || d < cutoff) { continue; }
  const source = String(row.source || '').trim();
  if (source === 'registration') {
    regCount += 1;
    const amt = parseFloat(String(row.amount_usd).replace(/[$,\s]/g, ''));
    if (!isNaN(amt)) { revenue += amt; }
  } else if (source === 'contact_us') {
    contactCount += 1;
    const cat = String(row.category || 'general').trim();
    if (catCounts[cat] !== undefined) { catCounts[cat] += 1; }
    if (String(row.sentiment || '').trim() === 'urgent') {
      urgent.push({ name: row.name || '(no name)', email: row.email || '(no email)', summary: row.summary || '' });
    }
  }
}

const total = regCount + contactCount;
const rangeStart = fmt(cutoff);
const rangeEnd = fmt(now);
const looker = String(cfg.looker_dashboard_url || '').trim();

let urgentHtml = '<p style="margin:6px 0;color:#666;">No urgent messages this week.</p>';
if (urgent.length > 0) {
  urgentHtml = '<ul style="margin:6px 0 6px 18px;padding:0;">' + urgent.map(function (u) {
    return '<li style="margin:2px 0;"><strong>' + u.name + '</strong> (' + u.email + '): ' + u.summary + '</li>';
  }).join('') + '</ul>';
}

const html =
  '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;color:#222;max-width:600px;">' +
  '<h2 style="margin:0 0 4px;">ArtHouse weekly summary</h2>' +
  '<p style="margin:0 0 12px;color:#666;">' + rangeStart + ' to ' + rangeEnd + '</p>' +
  '<p style="margin:6px 0;"><strong>' + total + '</strong> new form entries this week (' + regCount + ' registration, ' + contactCount + ' contact us).</p>' +
  '<p style="margin:6px 0;"><strong>Revenue this week:</strong> $' + (Math.round(revenue * 100) / 100).toFixed(2) + '</p>' +
  '<p style="margin:12px 0 4px;"><strong>Contact Us by category</strong></p>' +
  '<p style="margin:0 0 6px;">sponsor: ' + catCounts.sponsor + ', school: ' + catCounts.school + ', volunteer: ' + catCounts.volunteer + ', general: ' + catCounts.general + ', spam: ' + catCounts.spam + '</p>' +
  '<p style="margin:12px 0 4px;"><strong>Urgent messages</strong></p>' +
  urgentHtml +
  (looker ? '<p style="margin:14px 0 0;"><a href="' + looker + '">Open the Looker Studio dashboard</a></p>' : '') +
  '</div>';

const subject = 'ArtHouse weekly summary, ' + rangeStart + ' to ' + rangeEnd;

return [{
  json: {
    to: String(cfg.weekly_summary_recipient || '').trim(),
    subject: subject,
    html: html,
    total_entries: total,
    state_date: todayStr
  }
}];
